import { Node } from 'n8n-workflow';

function detectRecursiveAgents(workflow: any): string[] {
  const aiAgentNodes = workflow.nodes.filter((node: Node) => 
    node.type.includes('n8n-nodes-langchain.agent') || node.name.includes('AI Agent')
  );
  const triggerChains = [];

  aiAgentNodes.forEach((agentNode: Node) => {
    workflow.nodes.forEach((downstream: Node) => {
      if (downstream.parameters.webhookUrl?.includes(agentNode.id) || 
          downstream.parameters.url?.includes('agent')) {
        triggerChains.push(`Recursive loop: ${agentNode.name} -> ${downstream.name}`);
      }
    });
  });

  return triggerChains;
}

function detectStaleMemory(workflow: any): string[] {
  const memoryNodes = workflow.nodes.filter((node: any) => 
    node.type === 'n8n-nodes-base.chatMemory' || node.name.includes('Memory')
  );
  const issues = [];

  memoryNodes.forEach((memoryNode: any) => {
    const connectedAgents = workflow.connections[memoryNode.id]?.main?.length || 0;
    if (connectedAgents > 1) {
      issues.push(`Stale memory risk: ${memoryNode.name} shared across ${connectedAgents} agents`);
    }
  });

  return issues;
}

function scanCredentialExposure(workflow: any): string[] {
  const exposures = [];
  workflow.nodes.forEach((node: any) => {
    if (node.type.includes('agent') && node.parameters.tools) {
      node.parameters.tools.forEach((tool: any) => {
        if (tool.apiKey || tool.parameters?.match(/sk-\w{48}/)) {
          exposures.push(`Exposed credential in ${node.name}.${tool.name}`);
        }
      });
    }
  });
  return exposures;
}

