  const aiAgentOutput = execution.nodes['AI Agent'].output;

  // Vex detects coordination failures
  const issues = await vex.detect({
    framework: 'n8n',
    executionData: execution,
    agentOutput: aiAgentOutput,
    checks: ['recursive-execution', 'stale-memory', 'credential-exposure']
  });

  if (issues.length > 0) {
    // Auto-fix: inject validation
    await vex.remediate({
      workflowId: execution.workflow.id,
      fixes: ['add-output-validation', 'prevent-recursion']
    });
